import { useState } from "react";
import { ethers } from "ethers";
import { FLOWARC_ADDRESS, PAYSLIP_NFT_ADDRESS, FLOWARC_ABI, PAYSLIP_ABI, USDC_ABI, USDC_ADDRESS } from "./contracts/abis";
import EmployerDashboard from "./components/EmployerDashboard";
import WorkerDashboard from "./components/WorkerDashboard";
import PayslipViewer from "./components/PayslipViewer";

const ARC_CHAIN_ID = "0x4cef52";

function App() {
  const [address, setAddress]           = useState("");
  const [flowArc, setFlowArc]           = useState(null);
  const [payslipNFT, setPayslipNFT]     = useState(null);
  const [usdc, setUsdc]                 = useState(null);
  const [isEmployer, setIsEmployer]     = useState(false);
  const [activeTab, setActiveTab]       = useState("employer");
  const [loading, setLoading]           = useState(false);
  const [notification, setNotification] = useState(null);

  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 4000);
  };

  const switchToArc = async () => {
    try {
      await window.ethereum.request({
        method: "wallet_switchEthereumChain",
        params: [{ chainId: ARC_CHAIN_ID }],
      });
      return true;
    } catch (switchError) {
      if (switchError.code === 4902) {
        try {
          await window.ethereum.request({
            method: "wallet_addEthereumChain",
            params: [{
              chainId: ARC_CHAIN_ID,
              chainName: "Arc Testnet",
              rpcUrls: ["https://rpc.testnet.arc.network"],
              nativeCurrency: { name: "USDC", symbol: "USDC", decimals: 18 },
              blockExplorerUrls: ["https://testnet.arcscan.app"]
            }]
          });
          return true;
        } catch (e) {
          notify("Failed to add Arc Testnet to MetaMask", "error");
          return false;
        }
      }
      notify("Please switch to Arc Testnet in MetaMask", "error");
      return false;
    }
  };

  const connectWallet = async () => {
    if (!window.ethereum) return notify("Please install MetaMask!", "error");
    setLoading(true);
    try {
      await window.ethereum.request({ method: "eth_requestAccounts" });

      const switched = await switchToArc();
      if (!switched) { setLoading(false); return; }

      const _provider = new ethers.providers.Web3Provider(window.ethereum);
      const _signer   = _provider.getSigner();
      const _address  = await _signer.getAddress();

      const _flowArc    = new ethers.Contract(FLOWARC_ADDRESS, FLOWARC_ABI, _signer);
      const _payslipNFT = new ethers.Contract(PAYSLIP_NFT_ADDRESS, PAYSLIP_ABI, _signer);
      const _usdc       = new ethers.Contract(USDC_ADDRESS, USDC_ABI, _signer);

      const employerData = await _flowArc.employers(_address);
      setIsEmployer(employerData.registered);

      setAddress(_address);
      setFlowArc(_flowArc);
      setPayslipNFT(_payslipNFT);
      setUsdc(_usdc);
      notify("Wallet connected!");
    } catch (e) {
      notify(e.message, "error");
    }
    setLoading(false);
  };

  const shortAddress = (addr) => addr ? `${addr.slice(0, 6)}...${addr.slice(-4)}` : "";

  return (
    <div style={styles.app}>
      <div style={styles.header}>
        <div style={styles.logo}>
          <span style={styles.logoIcon}>⚡</span>
          <span style={styles.logoText}>FlowArc</span>
          <span style={styles.logoBadge}>Testnet</span>
        </div>
        {address ? (
          <div style={styles.walletBadge}>
            <span style={styles.dot} />
            {shortAddress(address)}
          </div>
        ) : (
          <button style={styles.connectBtn} onClick={connectWallet} disabled={loading}>
            {loading ? "Connecting..." : "Connect Wallet"}
          </button>
        )}
      </div>

      {notification && (
        <div style={{ ...styles.notification, background: notification.type === "error" ? "#ff4d4f" : "#00c48c" }}>
          {notification.msg}
        </div>
      )}

      {!address && (
        <div style={styles.hero}>
          <h1 style={styles.heroTitle}>Onchain Payroll for the <span style={styles.accent}>New Economy</span></h1>
          <p style={styles.heroSub}>Pay workers in USDC, stream salaries per second, mint payslip NFTs — all on Arc Testnet.</p>
          <button style={styles.heroBtn} onClick={connectWallet} disabled={loading}>
            {loading ? "Connecting..." : "Get Started →"}
          </button>
          <div style={styles.statsRow}>
            <div style={styles.stat}><span style={styles.statNum}>⚡</span><span>Instant USDC Payments</span></div>
            <div style={styles.stat}><span style={styles.statNum}>🎫</span><span>Payslip NFTs</span></div>
            <div style={styles.stat}><span style={styles.statNum}>🔒</span><span>Fully Onchain</span></div>
          </div>
        </div>
      )}

      {address && (
        <div style={styles.dashboard}>
          <div style={styles.tabs}>
            {["employer", "worker", "payslips"].map(tab => (
              <button
                key={tab}
                style={{ ...styles.tab, ...(activeTab === tab ? styles.activeTab : {}) }}
                onClick={() => setActiveTab(tab)}
              >
                {tab === "employer" ? "👔 Employer" : tab === "worker" ? "👷 Worker" : "🎫 Payslips"}
              </button>
            ))}
          </div>

          {activeTab === "employer" && (
            <EmployerDashboard
              flowArc={flowArc}
              usdc={usdc}
              address={address}
              isEmployer={isEmployer}
              setIsEmployer={setIsEmployer}
              notify={notify}
            />
          )}
          {activeTab === "worker" && (
            <WorkerDashboard
              flowArc={flowArc}
              address={address}
              notify={notify}
            />
          )}
          {activeTab === "payslips" && (
            <PayslipViewer
              payslipNFT={payslipNFT}
              address={address}
              notify={notify}
            />
          )}
        </div>
      )}
    </div>
  );
}

const styles = {
  app:         { minHeight: "100vh", background: "#0a0a0f", color: "#fff", fontFamily: "'Inter', sans-serif" },
  header:      { display: "flex", justifyContent: "space-between", alignItems: "center", padding: "20px 40px", borderBottom: "1px solid #1a1a2e" },
  logo:        { display: "flex", alignItems: "center", gap: "10px" },
  logoIcon:    { fontSize: "24px" },
  logoText:    { fontSize: "22px", fontWeight: "700", color: "#fff" },
  logoBadge:   { fontSize: "11px", background: "#1a1a2e", color: "#888", padding: "2px 8px", borderRadius: "20px" },
  walletBadge: { display: "flex", alignItems: "center", gap: "8px", background: "#1a1a2e", padding: "8px 16px", borderRadius: "20px", fontSize: "14px" },
  dot:         { width: "8px", height: "8px", borderRadius: "50%", background: "#00c48c" },
  connectBtn:  { background: "#5865f2", color: "#fff", border: "none", padding: "10px 24px", borderRadius: "8px", cursor: "pointer", fontWeight: "600" },
  notification:{ position: "fixed", top: "20px", right: "20px", padding: "12px 24px", borderRadius: "8px", color: "#fff", fontWeight: "600", zIndex: 1000 },
  hero:        { textAlign: "center", padding: "80px 20px" },
  heroTitle:   { fontSize: "48px", fontWeight: "800", lineHeight: 1.2, marginBottom: "20px" },
  accent:      { color: "#5865f2" },
  heroSub:     { fontSize: "18px", color: "#888", marginBottom: "40px", maxWidth: "600px", margin: "0 auto 40px" },
  heroBtn:     { background: "#5865f2", color: "#fff", border: "none", padding: "16px 40px", borderRadius: "12px", fontSize: "18px", cursor: "pointer", fontWeight: "700" },
  statsRow:    { display: "flex", justifyContent: "center", gap: "40px", marginTop: "60px" },
  stat:        { display: "flex", flexDirection: "column", alignItems: "center", gap: "8px", color: "#888" },
  statNum:     { fontSize: "28px" },
  dashboard:   { maxWidth: "900px", margin: "0 auto", padding: "40px 20px" },
  tabs:        { display: "flex", gap: "10px", marginBottom: "30px" },
  tab:         { background: "#1a1a2e", color: "#888", border: "none", padding: "12px 24px", borderRadius: "8px", cursor: "pointer", fontWeight: "600", fontSize: "14px" },
  activeTab:   { background: "#5865f2", color: "#fff" },
};

export default App;
